const timestamp = new Date().toISOString();
return [{
  json: {
    status: 'completed',
    message: 'No hay alquileres pendientes ni audit',
    total_procesadas: 0,
    pending_confirmadas: 0,
    audit_c21_terminadas: 0,
    audit_remax_terminadas: 0,
    skipped: 0,
    timestamp
  }
}];

const prop = $input.first().json;
if (prop.origen === 'audit') {
  return [{ json: { ...prop, _needsHttp: true } }];
} else {
  return [{ json: { ...prop, _needsHttp: false } }];
}

// ============================================================================
// Verificador Alquiler v2.0 - Procesar respuesta
// Pending: auto-confirmación por tiempo (2 días)
// Audit: verificar status code (C21: 404, Remax: 302)
// ============================================================================

const item = $input.first();
const originalData = item.json;

let propiedadData;
try {
  propiedadData = $('Router origen').first().json;
} catch(e) {
  propiedadData = originalData;
}

const origen = propiedadData.origen;
const fuente = propiedadData.fuente;
const diasDesdeAusencia = propiedadData.dias_desde_ausencia || 0;
const primeraAusenciaAt = propiedadData.primera_ausencia_at;

const MAX_DIAS_PENDING = 2;

let action = 'skip';
let newStatus = null;
let reason = '';
let razonInactiva = 'aviso_terminado';

// ============================================================================
// PENDING: solo auto-confirmación por tiempo
// ============================================================================
if (origen === 'pending') {
  if (!primeraAusenciaAt) {
    action = 'skip';
    reason = 'ERROR: primera_ausencia_at es NULL';
  } else if (diasDesdeAusencia >= MAX_DIAS_PENDING) {
    action = 'confirm';
    newStatus = 'inactivo_confirmed';
    razonInactiva = 'aviso_terminado';
    reason = `Auto-confirmado: ${diasDesdeAusencia} días ausente (límite: ${MAX_DIAS_PENDING})`;
  } else {
    action = 'skip';
    reason = `Esperando: día ${diasDesdeAusencia}/${MAX_DIAS_PENDING}`;
  }
}

// ============================================================================
// AUDIT: verificar status code (C21: 404, Remax: 302)
// ============================================================================
else if (origen === 'audit') {
  const statusCode = originalData.statusCode || 0;
  const isError = !!originalData.error;

  if (isError) {
    action = 'skip';
    reason = `Audit: error HTTP - skip`;

  } else if (fuente === 'century21') {
    if (statusCode === 404) {
      action = 'confirm';
      newStatus = 'inactivo_confirmed';
      razonInactiva = 'audit_c21_terminado';
      reason = `Audit C21: HTTP 404 - Aviso terminado`;
    } else {
      action = 'skip';
      reason = `Audit C21: HTTP ${statusCode} - página activa`;
    }

  } else if (fuente === 'remax') {
    if (statusCode === 301 || statusCode === 302) {
      action = 'confirm';
      newStatus = 'inactivo_confirmed';
      razonInactiva = 'audit_remax_redirect';
      reason = `Audit Remax: redirect HTTP ${statusCode} detectado`;
    } else {
      action = 'skip';
      reason = `Audit Remax: HTTP ${statusCode} - página activa`;
    }

  } else {
    action = 'skip';
    reason = `Audit: fuente ${fuente} no soportada`;
  }
}

return [{
  json: {
    id: propiedadData.id,
    url: propiedadData.url,
    fuente: fuente,
    codigo_propiedad: propiedadData.codigo_propiedad,
    primera_ausencia_at: primeraAusenciaAt,
    action,
    newStatus,
    reason,
    razonInactiva,
    origen,
    diasDesdeAusencia,
    maxDiasPending: MAX_DIAS_PENDING,
    timestamp: new Date().toISOString()
  }
}];

// ============================================================================
// Verificador Alquiler v2.0 - Resumen final
// ============================================================================

const results = $input.first().json.results || [];

let pending_confirmadas = 0;
let audit_c21 = 0;
let audit_remax = 0;
let skipped = 0;

for (const r of results) {
  if (r.action === 'confirm' && r.origen === 'pending') pending_confirmadas++;
  else if (r.action === 'confirm' && r.razonInactiva === 'audit_c21_terminado') audit_c21++;
  else if (r.action === 'confirm' && r.razonInactiva === 'audit_remax_redirect') audit_remax++;
  else skipped++;
}

return [{
  json: {
    status: 'completed',
    flujo: 'Verificador Alquiler v2.0',
    timestamp: new Date().toISOString(),
    total_procesadas: results.length,
    pending_confirmadas,
    audit_c21_terminadas: audit_c21,
    audit_remax_terminadas: audit_remax,
    total_confirmadas: pending_confirmadas + audit_c21 + audit_remax,
    skipped,
    detalles: results
      .filter(r => r.action === 'confirm')
      .map(r => `#${r.id} (${r.fuente}): ${r.razonInactiva || r.razon_inactiva || 'confirmado'}`)
  }
}];
